import os, json
from supabase import create_client
sb = create_client(os.environ['SUPABASE_URL'], os.environ['SUPABASE_SERVICE_KEY'])
rows = sb.table('sai_memory').select('content').eq('category','position_mastery').execute()

# Check which clusters in Marketing, Content, Legal, Sales are well-covered vs thin
families = {}
for r in rows.data:
    try:
        d = json.loads(r['content']) if isinstance(r['content'], str) else r['content']
        fam = d.get('cluster_family','?')
        clu = d.get('cluster_name','?')
        pos = d.get('position_name','?')
        if fam not in families:
            families[fam] = {}
        if clu not in families[fam]:
            families[fam][clu] = []
        families[fam][clu].append(pos)
    except:
        pass

target_fams = ['Marketing & Advertising', 'Content & Communications', 'Legal & Compliance', 'Sales & Revenue']
for fam in sorted(families.keys()):
    if any(t.lower() in fam.lower() for t in ['marketing','content','legal','sales']):
        print(f'\n=== {fam} ===')
        for clu in sorted(families[fam].keys()):
            positions = families[fam][clu]
            print(f'  {clu}: {len(positions)} positions')
            for p in positions:
                print(f'    - {p}')
